practice_tasks.solution:
def db_insert(username):
    raise KeyError('Duplicate key')

def create_user(username):
    try:
        db_insert(username)
    except KeyError as e:
        raise ValueError('User exists') from e

code_walkthrough.code:
def parse_config(data):
    try:
        return int(data['port'])
    except (KeyError, ValueError) as e:
        raise RuntimeError("Invalid config file") from e

try:
    parse_config({})
except RuntimeError as e:
    print(f"High-level error: {e}")
    print(f"Low-level root cause: {type(e.__cause__).__name__}")

challenge.solution:
class ServiceUnavailableError(Exception): pass

try:
    try:
        raise ConnectionError('Socket timeout')
    except ConnectionError:
        raise ServiceUnavailableError('Service down') from None
except ServiceUnavailableError as e:
    print(f'{e}, cause: {e.__cause__}')

